const query = $json.query || {};
const body = $json.body || $json;
const message = query.message || body.message || body.goal || '';
const projectId = query.project_id || body.project_id || ('proj-' + Date.now());
const reference_url = query.reference_url || body.reference_url || null;
const image_data = body.image_data || null;
return [{ json: { message, project_id: projectId, operation: 'init', goal: message, reference_url, image_data } }];

const operation = $json.operation || 'get';
const projectId = $json.project_id;
if (!projectId) return [{ json: { error: 'project_id required' } }];
const store = $getWorkflowStaticData('global');
if (operation === 'init') {
  if (store[projectId]) return [{ json: { ...store[projectId], already_exists: true } }];
  store[projectId] = {
    project_id: projectId,
    goal: $json.goal || '',
    status: 'active',
    completed_tasks: [],
    pending_tasks: [],
    files: [],
    created_at: new Date().toISOString(),
    last_updated: new Date().toISOString()
  };
  return [{ json: store[projectId] }];
}
if (operation === 'get') {
  return [{ json: store[projectId] || { project_id: projectId, exists: false } }];
}
if (operation === 'set') {
  const existing = store[projectId] || {};
  store[projectId] = { ...existing, ...$json.state, project_id: projectId, last_updated: new Date().toISOString() };
  return [{ json: store[projectId] }];
}
return [{ json: { error: `Unknown operation: ${operation}` } }];

// MODIFIED: Absorbs Research: Build Project Context
// Caches _allFileContents, _researchDocs, _projectFileList in static data
// so Phase 2 chunks don't need to re-fetch or re-compute.
const memory = $('Init Memory').first().json;
const message = $('Extract Input').first().json.message;
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');

// Cache all file contents for Phase 2
staticData._allFileContents = allFiles;

const fileList = allFiles.map(f => f.path);

// Build API surface (exports from each file)
const apiSurface = [];
for (const f of allFiles) {
  if (!f.path.match(/\.(ts|tsx|js|jsx)$/) || f.path.includes('node_modules')) continue;
  const lines = (f.content || '').split('\n');
  const exports = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^export\s+default\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').substring(0, 120));
    } else if (/^export\s+(const|let|var|function|class|interface|type|enum)\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').replace(/=>[\s\S]*$/, '=> ...').substring(0, 150));
    } else if (/^export\s+\{/.test(trimmed)) {
      exports.push(trimmed.substring(0, 150));
    }
  }
  if (exports.length > 0) {
    apiSurface.push(`## ${f.path}\n${exports.join('\n')}`);
  }
}

// Extract dependencies from package.json
let dependencies = {};
let devDependencies = {};
let depNames = [];
for (const f of allFiles) {
  if (f.path === 'package.json' || f.path.endsWith('/package.json')) {
    try {
      const pkg = JSON.parse(f.content);
      dependencies = { ...dependencies, ...(pkg.dependencies || {}) };
      devDependencies = { ...devDependencies, ...(pkg.devDependencies || {}) };
      depNames = [...Object.keys(pkg.dependencies || {}), ...Object.keys(pkg.devDependencies || {})];
    } catch(e) {}
  }
}

// Build research docs string
const depList = Object.entries(dependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
const devDepList = Object.entries(devDependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
let researchDocs = '';
if (depList || devDepList) {
  researchDocs += '## Dependency Manifest\nOnly use packages listed here.\n';
  if (depList) researchDocs += `dependencies:\n${depList}\n`;
  if (devDepList) researchDocs += `devDependencies:\n${devDepList}\n`;
}
if (apiSurface.length > 0) {
  researchDocs += '\n## Project API Surface\nMatch these import/export signatures exactly when importing from project files.\n';
  researchDocs += apiSurface.join('\n\n');
}

// Cache for all downstream phases
staticData._researchDocs = researchDocs;
staticData._projectFileList = fileList;
staticData._projectApiSummary = apiSurface.join('\n');
staticData._projectDeps = depNames;

return [{ json: {
  message,
  project_goal: memory.goal || message,
  project_id: memory.project_id,
  existing_files: fileList,
  api_summary: apiSurface.join('\n'),
  installed_packages: depNames
} }];

const message = $json.message || '';
const existingFiles = $json.existing_files || [];
const apiSummary = $json.api_summary || '';
const installedPkgs = $json.installed_packages || [];
const scrapeData = $json._scrapeData;

let projectContext = '';
if (existingFiles.length > 0) {
  projectContext += `\n\nEXISTING PROJECT FILES (only reference files from this list):\n${existingFiles.join('\n')}\n`;
}
if (apiSummary) {
  projectContext += `\nAPI SURFACE (exports from each file):\n${apiSummary}\n`;
}
if (installedPkgs.length > 0) {
  projectContext += `\nINSTALLED PACKAGES (only reference packages from this list):\n${installedPkgs.join(', ')}\n`;
}

const plannerPrompt = `You are a Senior Software Architect and UI/UX Design Expert. Your job is to break a coding request into MULTIPLE structured tasks with detailed visual specifications.

DESIGN PRINCIPLES (apply to ALL task descriptions):
- Main interaction element must be centered and dominant (40-60% of viewport height)
- Use vertical single-column layouts for apps/games — never side-by-side grids unless explicitly requested
- Content hierarchy: hero/main action at top → stats/feedback → secondary actions (shop, settings) at bottom
- Mobile-first: everything fits in 100vh, no page-level scrollbars, internal scrolling only for lists
- Dark backgrounds with bright accent colors. Use gradients for depth (purple-900 to black, not flat colors)
- Every click/tap must produce visible feedback (scale animation, color flash, particle effect)
- Numbers should animate when they change (bounce, pulse, scale). Use tabular-nums for counters
- Cards: rounded-xl (12-16px), subtle shadows, semi-transparent backgrounds with backdrop-blur
- Buttons: press animation (scale 0.95), hover glow, disabled state with reduced opacity
- Color-code affordability: gold/amber = available, red/gray = locked, green = owned/success
- Typography: big bold numbers (text-4xl+), clear hierarchy via weight not just size
- Spacing: generous padding, never cramped. Mobile touch targets minimum 44px

WHEN A REFERENCE IMAGE IS PROVIDED:
- Describe the EXACT layout structure you see: column vs row, spacing ratios, component sizes
- Specify exact colors, gradients, border styles, and shadows visible in the image
- Note the visual hierarchy: what's biggest, what's brightest, what draws the eye first
- Describe animations or interactive states implied by the design (hover effects, active states)
- Include specific dimensions: "toilet button should be 150px diameter" not just "large button"
- The coder CANNOT see the image — your description is their ONLY reference Each task will be handled by a separate coder with 128K context who can write up to 6 files at once.\n\nOutput a JSON object with ONE field:\n\n"tasks": array of task objects. IMPORTANT: You MUST create multiple tasks. Group files by concern (e.g. styles in one task, frontend components in another, config in another). Each task has:\n- task_id: string like "TASK-001"\n- description: detailed actionable description of what to implement, including specific requirements, color values, component names, API endpoints, and behavior. The coder cannot see the original request — your description is all they get.\n- files: array of exact file paths to create or modify. List EVERY file this task needs — the coder can ONLY write files listed here. For existing projects, prefer modifying files from the EXISTING PROJECT FILES list. For new projects or missing functionality, CREATE new file paths as needed.\n- dependencies: array of task_id strings this task depends on (empty if none)\n- complexity: "low", "medium", or "high"
- needs_concept: boolean — set to true if this task involves UI/visual work that has NO reference image from the user. Set to false if the user provided a reference image that covers this task's visual design, or if the task is purely logic/config with no visual component.\n\nRULES:\n- Always split work across multiple tasks by concern: styles, components, routes, config, etc.\n- Each task can touch up to 12-15 files. The coder has 128K context and currently uses less than 2% of it — give it MORE work per task. Aim for 2-3 LARGE tasks instead of many small ones. A single task can contain an entire feature (components + hooks + styles + config). Fewer tasks = faster pipeline\n- The description must be SELF-CONTAINED — include ALL details the coder needs\n- For existing projects, reference files from the EXISTING PROJECT FILES list when modifying. You MAY create new files that do not exist yet.
- CRITICAL: For new projects (empty file list), you MUST include a setup task that creates: package.json (with ALL dependencies), index.html, vite.config.js (or next.config.js), tsconfig.json (if TypeScript), tailwind.config.js + postcss.config.js (if using Tailwind), and the main entry point (src/main.jsx or app/layout.tsx). The project MUST be buildable.\n- Detect the project type from the files and packages. If the project is a React/Vite frontend (no Express or backend framework in INSTALLED PACKAGES), focus all tasks on frontend files. Only create server/middleware/API handler tasks if Express or a similar backend framework is in INSTALLED PACKAGES.\n- In each task description, specify the EXACT import/export style each file should use (named vs default) based on the API SURFACE above.\n- NEVER create a task whose only purpose is deleting files. The coder cannot delete files — it can only create or modify. If dead files exist, ignore them. They do not affect the build.
- The FIRST task should always include project configuration files (package.json, config files, index.html) if they do not already exist. The project MUST compile and run after all tasks complete.
- Output ONLY the raw JSON object: {"tasks": [...]}\n- No markdown, no explanation — ONLY the JSON with tasks`;

let messageContent;
if (scrapeData && scrapeData.screenshot_b64) {
  const cssTokensStr = JSON.stringify(scrapeData.css_tokens, null, 2);
  const domStr = scrapeData.dom_summary || '';
  messageContent = [
    { type: 'image_url', image_url: { url: `data:image/png;base64,${scrapeData.screenshot_b64}` } },
    { type: 'text', text: `${plannerPrompt}\n\nREFERENCE DESIGN (screenshot above):\nCSS Tokens:\n${cssTokensStr}\n\nDOM Structure:\n${domStr}\n\nRequest: ${message}${projectContext}\n\n(Match the visual design, color palette, typography, and layout from the screenshot)` }
  ];
} else if ($('Extract Input').first().json.image_data) {
  const userImage = $('Extract Input').first().json.image_data;
  messageContent = [
    { type: 'image_url', image_url: { url: 'data:image/png;base64,' + userImage } },
    { type: 'text', text: plannerPrompt + '\n\nREFERENCE IMAGE (uploaded by user — replicate this design):\n\nRequest: ' + message + projectContext }
  ];
} else {
  messageContent = `${plannerPrompt}\n\nRequest: ${message}${projectContext}`;
}

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{ role: 'user', content: messageContent }],
    temperature: parseFloat($env.PLANNER_TEMP) || 0.7,
    top_p: parseFloat($env.PLANNER_TOP_P) || 0.9,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 8192
  }
}];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/<\/?task>/g, '').trim();
content = content.replace(/\n+(?:Reasoning|Note|Explanation):[\s\S]*/i, '').trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let tasks, planDocument = '';
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed)) {
    tasks = parsed;
  } else {
    tasks = parsed.tasks || [parsed];
    planDocument = parsed.plan_document || '';
  }
} catch (e) {
  // Truncated JSON recovery: extract complete task objects
  const tasksMatch = content.match(/"tasks"\s*:\s*\[/);
  if (tasksMatch) {
    const arrStart = content.indexOf('[', tasksMatch.index);
    let bracketDepth = 0;
    let lastCompleteObj = -1;
    for (let i = arrStart; i < content.length; i++) {
      if (content[i] === '{') bracketDepth++;
      if (content[i] === '}') {
        bracketDepth--;
        if (bracketDepth === 0) lastCompleteObj = i;
      }
    }
    if (lastCompleteObj > arrStart) {
      const recoveredArr = content.substring(arrStart, lastCompleteObj + 1) + ']';
      try {
        tasks = JSON.parse(recoveredArr);
      } catch (e2) {
        tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
      }
    } else {
      tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
    }
  } else {
    tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
  }
}

tasks = tasks.map(t => ({
  ...t,
  files: t.files || [],
  dependencies: t.dependencies || [],
  complexity: t.complexity || 'medium'
}));

return [{ json: { tasks, plan_document: planDocument } }];

// MODIFIED: Absorbs Split Into Chunks. Builds flat (task, chunk) queue.
// Queue is passed through data pipeline (not static data) to avoid stale reads after HTTP nodes.
const tasks = $json.tasks || [];
const planDocument = $json.plan_document || '';
const plannerInput = $('Prepare Planner Input').first().json;
const projectId = plannerInput.project_id;
const projectGoal = plannerInput.project_goal;

// Topological sort
const taskMap = new Map();
tasks.forEach(t => taskMap.set(t.task_id, t));
const inDegree = new Map();
const dependents = new Map();
tasks.forEach(t => {
  inDegree.set(t.task_id, 0);
  dependents.set(t.task_id, []);
});
tasks.forEach(t => {
  const deps = (t.dependencies || []).filter(d => taskMap.has(d));
  inDegree.set(t.task_id, deps.length);
  deps.forEach(d => dependents.get(d).push(t.task_id));
});
const topoQueue = [];
tasks.forEach(t => {
  if (inDegree.get(t.task_id) === 0) topoQueue.push(t.task_id);
});
const sorted = [];
while (topoQueue.length > 0) {
  const id = topoQueue.shift();
  sorted.push(taskMap.get(id));
  for (const dep of (dependents.get(id) || [])) {
    inDegree.set(dep, inDegree.get(dep) - 1);
    if (inDegree.get(dep) === 0) topoQueue.push(dep);
  }
}
if (sorted.length < tasks.length) {
  const sortedIds = new Set(sorted.map(t => t.task_id));
  tasks.forEach(t => { if (!sortedIds.has(t.task_id)) sorted.push(t); });
}

// Flatten into (task, chunk) queue — 2 files per chunk
const chunkSize = 15;
const queue = [];
for (const task of sorted) {
  const taskFiles = task.files || [];
  const chunks = [];
  for (let i = 0; i < taskFiles.length; i += chunkSize) {
    chunks.push(taskFiles.slice(i, i + chunkSize));
  }
  if (taskFiles.length === 0) continue;  // skip tasks with no files assigned
  for (const chunkFiles of chunks) {
    queue.push({
      task,
      chunk_files: chunkFiles,
      project_id: projectId,
      project_goal: projectGoal,
      plan_document: planDocument
    });
  }
}

const staticData = $getWorkflowStaticData('global');
staticData.p2Results = [];
staticData.allTasks = sorted;
staticData._queueTotal = queue.length;
staticData._queueDone = 0;

if (queue.length === 0) {
  return [{ json: { task: { task_id: 'NONE', description: 'No tasks', files: [] }, chunk_files: [], project_id: projectId, project_goal: projectGoal, plan_document: planDocument, _p2Queue: [] } }];
}
// Pass remaining queue items through data pipeline instead of static data
const first = queue[0];
first._p2Queue = queue.slice(1);
return [{ json: first }];

// P2: Stash Context — passes through all fields including _p2Queue for loop control
const staticData = $getWorkflowStaticData('global');
staticData._currentProjectId = $json.project_id;
staticData._currentTaskId = ($json.task || {}).task_id || '';
staticData._currentTask = $json.task || null;
staticData._currentProjectGoal = $json.project_goal || '';
staticData._currentQueue = $json._p2Queue || [];  // snapshot queue for this iteration
return [{ json: {
  task: $json.task,
  chunk_files: $json.chunk_files,
  project_id: $json.project_id,
  project_goal: $json.project_goal,
  plan_document: $json.plan_document,
  _p2Queue: $json._p2Queue || []
} }];

// Builds coder input — task files in full, other files as compact summaries
const staticData = $getWorkflowStaticData('global');
const stashed = $json;
const taskFiles = (stashed.task || {}).files || stashed.chunk_files || [];
const allFiles = staticData._allFileContents || [];

// Full content for files in THIS task + closely related files (imports)
const taskFileSet = new Set(taskFiles.map(f => typeof f === 'string' ? f : f.path));

// Also include files that task files import from
for (const file of allFiles) {
  if (taskFileSet.has(file.path)) {
    // Find imports in this file
    const importMatches = (file.content || '').matchAll(/from\s+['"]([^'"]+)['"]/g);
    for (const m of importMatches) {
      const importPath = m[1];
      if (importPath.startsWith('.')) {
        // Resolve relative import to find the actual file
        const dir = file.path.replace(/\/[^\/]+$/, '');
        const resolved = importPath.replace(/^\.\//,'').replace(/^\.\.\//, '');
        for (const f of allFiles) {
          if (f.path.includes(resolved) || f.path.replace(/\.(ts|tsx|js|jsx)$/, '').endsWith(resolved)) {
            taskFileSet.add(f.path);
          }
        }
      }
    }
  }
}

// Always include package.json and main config files (small, critical for context)
const alwaysInclude = ['package.json', 'tsconfig.json', 'vite.config.js', 'tailwind.config.js', 'postcss.config.js', 'index.html'];
for (const f of alwaysInclude) {
  const match = allFiles.find(a => a.path === f || a.path.endsWith('/' + f));
  if (match) taskFileSet.add(match.path);
}

// Split: full content for task files, compact for everything else
const fullFiles = [];
const summaryFiles = [];
for (const file of allFiles) {
  if (file.path.includes('node_modules')) continue;
  if (taskFileSet.has(file.path)) {
    fullFiles.push(file);
  } else if (file.path.match(/\.(ts|tsx|js|jsx|css|json|html)$/)) {
    // Compact summary: path + first line (exports) + size
    const firstLines = (file.content || '').split('\n').slice(0, 3).join('\n');
    const exports = (file.content || '').match(/export\s+(default\s+)?(?:function|const|class)\s+(\w+)/g) || [];
    summaryFiles.push({
      path: file.path,
      summary: exports.join(', ') || firstLines.substring(0, 100),
      size: (file.content || '').length
    });
  }
}

const existingFiles = fullFiles;

const task = { ...(stashed.task || {}) };
if (taskFiles.length > 0) task.files = taskFiles;

return [{ json: {
  task,
  existing_files: existingFiles,
  other_files_summary: summaryFiles,
  plan_document: stashed.plan_document || '',
  project_goal: stashed.project_goal || '',
  project_id: stashed.project_id,
  research_docs: staticData._researchDocs || ''
} }];

// MODIFIED: Removed retry/feedback logic (that's Phase 4 now)
// Removed hardcoded tech stack, uses positive language
const input = $json;
const planDocument = input.plan_document || '';

let taskDescription = input.task?.description || input.description || '';
if (!taskDescription && input.task?.raw_output) {
  const raw = input.task.raw_output;
  const cleaned = raw.replace(/<\/?task>/g, '').replace(/\n+(?:Reasoning|Note):[\s\S]*/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    const list = Array.isArray(parsed) ? parsed : (parsed.tasks || []);
    taskDescription = list.map(t => `${t.task_id}: ${t.description}`).join('\n\n');
  } catch(e) { taskDescription = raw; }
}

const taskFiles = (input.task || {}).files || [];
const filesConstraint = taskFiles.length > 0
  ? '\n\nFILES TO MODIFY (only output these files):\n' + taskFiles.join('\n')
  : '';

const existingFiles = input.existing_files || [];
const otherFilesSummary = input.other_files_summary || [];
const existingFilesSection = existingFiles.length > 0
  ? '\n\nFULL PROJECT CONTEXT (all files in the project — read these for context but ONLY output files listed in FILES TO MODIFY):\n' +
    (() => { let total = 0; const MAX = 40000; return existingFiles.filter(f => { const size = f.path.length + (f.content||'').length + 20; if (total + size > MAX) return false; total += size; return true; }).map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n'); })() + (otherFilesSummary.length > 0 ? '\n\nOTHER PROJECT FILES (not shown in full — reference only):\n' + otherFilesSummary.map(f => `- ${f.path} (${f.size} chars): ${f.summary}`).join('\n') : '')
  : '';

const researchDocs = input.research_docs || '';
const hasDependencyManifest = researchDocs.includes('## Dependency Manifest');
const depRule = hasDependencyManifest
  ? '- CRITICAL: Only use packages found in the Dependency Manifest below. If you need functionality from a package not in the manifest, use built-in browser/Node APIs or the listed packages instead.'
  : '- CRITICAL: No package.json exists yet. Only use packages that are explicitly named in the Task description above. For anything not named, use built-in browser/Node APIs instead.';

// Detect image assets in public/assets/ — tell the coder to USE them
const assetFiles = existingFiles
  .filter(f => f.path.match(/^public\/assets\/.*\.(png|jpg|jpeg|svg|gif|webp)$/i))
  .map(f => f.path);
const assetWarning = assetFiles.length > 0
  ? '\n\n⚠️ GAME ASSETS AVAILABLE IN public/assets/ — YOU MUST USE THESE:\n' +
    assetFiles.map(a => {
      const webPath = '/' + a.replace('public/', '');
      return `- ${a} → use as: <img src="${webPath}" />`;
    }).join('\n') +
    '\n\nCRITICAL: Use <img src="/assets/..."> tags for these images. Do NOT create inline SVGs, do NOT use emoji characters, do NOT generate new icons. These are real game-quality PNG/SVG assets ready to use.\nExample: <img src="/assets/toilet_face_on.png" className="w-[200px]" alt="toilet" />'
  : '';

const userContent = `Task:\n${taskDescription}${assetWarning}${filesConstraint}${existingFilesSection}`;

let systemMessage = `You are a Senior Full-Stack Developer. Output ONLY the files that need to be created or changed. Skip files that are already correct.\n\nFor EACH file you need to create or modify, output EXACTLY this format:\n### path/to/file.ts\n\`\`\`ts\n[complete file content]\n\`\`\`\n\nRULES:\n- Only output files that this task requires you to create or change\n- Output complete file content (not diffs)\n- No explanations, no numbered lists, no prose — ONLY the file blocks\n- Only output files listed in the FILES TO MODIFY section\n- CRITICAL: Implement EXACTLY what the Task specifies. Use the exact text strings, component names, props, and content listed. Never substitute generic placeholders for specified content.\n- ${depRule.replace(/^- /, '')}\n- CRITICAL: Match import styles to the source module. Use named imports ({ X }) for named exports, default imports for default exports. Check the EXISTING PROJECT FILES to confirm each module's export style.\n- Preserve each file's existing export style (named vs default) when modifying it\n- CRITICAL: Files containing JSX/TSX syntax (React components, JSX elements) MUST use .tsx extension, NOT .ts. Using .ts for JSX will break the build. If a task says to create 'component.ts' but the content has JSX, change it to 'component.tsx'.\n- NEVER create both .ts and .tsx versions of the same file. If a file exists as .tsx, write to .tsx only.`;

if (planDocument) {
  systemMessage += `\n\nARCHITECTURE REFERENCE (follow this plan):\n${planDocument}`;
}

if (researchDocs) {
  systemMessage += `\n\nPROJECT CONTEXT (from research agent):\n${researchDocs.substring(0, 8000)}`;
}

// Load task-specific Stitch concept (if available)
const taskId = (input.task || {}).task_id || '';
const taskConcepts = $getWorkflowStaticData('global')._taskConcepts || {};
const taskConcept = taskConcepts[taskId] || null;

// Load reference images for VL coder — it can SEE the design target
const http = require('http');
const projectId = input.project_id || $('Extract Input').first().json.project_id || '';
const FILE_API = ($env.FILE_API_URL || 'http://file-api:3456').replace('http://', '');
const [apiHost, apiPort] = FILE_API.split(':');
const refImages = await new Promise((resolve) => {
  const req = http.request({
    hostname: apiHost, port: parseInt(apiPort) || 3456,
    path: `/projects/${projectId}/references`,
    method: 'GET',
    headers: { 'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || '') },
    timeout: 10000
  }, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => { try { resolve(JSON.parse(data).references || []); } catch { resolve([]); } });
  });
  req.on('error', () => resolve([]));
