      if (resolveText.includes('Failed to retrieve')) { errors.push(lib + ': ctx7 failed'); continue; }
      const idMatch = resolveText.match(/Context7-compatible library ID:\s*(\/[\w.-]+\/[\w.-]+)/);
      if (!idMatch) { errors.push(lib + ': no ID'); continue; }

      const docsResp = await mcpRequest(sid, 'tools/call', {
