const [mcpHost, mcpPortStr] = MCP_URL_HOST.split(':');
const mcpPort = parseInt(mcpPortStr) || 8811;
let _mcpSessionId = null;

function mcpCall(method, params) {
  return new Promise((resolve) => {
    const body = JSON.stringify({ jsonrpc: '2.0', method, params, id: Date.now() });
    const headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json, text/event-stream',
      'Content-Length': Buffer.byteLength(body),
    };
    if (_mcpSessionId) headers['Mcp-Session-Id'] = _mcpSessionId;
    const req = http.request({ hostname: mcpHost, port: mcpPort, path: '/mcp', method: 'POST', headers, timeout: 60000 }, (res) => {
      if (!_mcpSessionId && res.headers['mcp-session-id']) _mcpSessionId = res.headers['mcp-session-id'];
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        // Parse SSE format
        for (const line of data.split('\n')) {
          if (line.startsWith('data:')) {
            try { return resolve(JSON.parse(line.slice(5))); } catch {}
          }
        }
        try { resolve(JSON.parse(data)); } catch { resolve({ error: data }); }
      });
    });
    req.on('error', e => resolve({ error: e.message }));
    req.on('timeout', () => { req.destroy(); resolve({ error: 'timeout' }); });
    req.write(body);
    req.end();
  });
}

