    }

    const genRes = await stitchCall({
      name: 'generate_screen_from_text',
      arguments: {
        projectId: stitchProjectId,
        prompt: prompt,
        deviceType: 'MOBILE',
        modelId: 'GEMINI_3_FLASH',
      }
    });

    const genText = genRes?.result?.content?.[0]?.text || '';
    const genInfo = JSON.parse(genText);
    const screens = genInfo.outputComponents?.[0]?.design?.screens || [];
    const screenshotUrl = screens[0]?.screenshot?.downloadUrl;

    if (screenshotUrl) {
      const b64 = await downloadImage(screenshotUrl);
      if (b64 && b64.length > 100) {
        concepts[task.task_id] = b64;
      }
    }

    // After first screen: extract design context for consistency
    if (i === 0 && screens.length > 0) {
      try {
        const contextRes = await stitchCall({
          name: 'get_design_context',
          arguments: {
            projectId: stitchProjectId,
            screenName: screens[0]?.name || 'Screen 1'
          }
        });
        const contextText = contextRes?.result?.content?.[0]?.text || '';
        if (contextText.length > 50) {
          designContext = contextText.substring(0, 500);
        }
      } catch(e) {
        // Design context extraction failed — continue without it
      }
    }
  } catch(e) {
    // Skip this task's concept
  }
}

staticData._taskConcepts = concepts;

// Callback
try {
  const http = require('http');
  const count = Object.keys(concepts).length;
  const cbBody = JSON.stringify({
    event: 'stitch_complete',
    project_id: projectId,
    data: { message: '🎨 Generated ' + count + ' task concepts' + (designContext ? ' (consistent design system)' : ''), count }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody); req.end();
} catch {}

return [{ json: $json }];

// Pass to fixer if fixes needed, empty otherwise
if (!$json._needsFix) return [];
return [{ json: $json }];

// Pass to final review if NO fixes needed, empty otherwise
if ($json._needsFix) return [];
return [{ json: $json }];

