import React, { useState, useEffect, useRef } from 'react';
import './styles/animations.css';
import { useGame } from '../context/GameContext';

interface PoopParticle {
  id: number;
  x: number;
  y: number;
  velocityX: number;
  velocityY: number;
  rotation: number;
}

const GameScreen: React.FC = () => {
  const { poopCount, clickPower, perSecond, handleClick } = useGame();
  const [bounceAnimation, setBounceAnimation] = useState(false);
  const [particles, setParticles] = useState<PoopParticle[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);

  // Initialize particles
  useEffect(() => {
    const newParticles: PoopParticle[] = [];
    const particleCount = 15;

    for (let i = 0; i < particleCount; i++) {
      newParticles.push({
        id: i,
        x: Math.random() * 100, // percentage
        y: Math.random() * 100, // percentage
        velocityX: (Math.random() - 0.5) * 2, // random horizontal speed
        velocityY: Math.random() * 2 + 1, // downward speed
        rotation: Math.random() * 360,
      });
    }

    setParticles(newParticles);
  }, []);

  // Update particles animation
  useEffect(() => {
    const interval = setInterval(() => {
      setParticles((prevParticles) =>
        prevParticles.map((particle) => {
          let newX = particle.x + particle.velocityX * 0.2;
          let newY = particle.y + particle.velocityY * 0.2;
          let newRotation = particle.rotation + 2;

          // Reset if out of bounds
          if (newY > 110) {
            newX = Math.random() * 100;
            newY = -10;
            newRotation = Math.random() * 360;
          }

          return {
            ...particle,
            x: newX,
            y: newY,
            rotation: newRotation,
          };
        })
      );
    }, 50);

    return () => clearInterval(interval);
  }, []);

  const handleToiletClick = () => {
    // Animate count with bounce
    setBounceAnimation(true);
    setTimeout(() => setBounceAnimation(false), 300);

    // Add particles
    const newParticles: PoopParticle[] = [];
    for (let i = 0; i < 5; i++) {
      newParticles.push({
        id: Date.now() + i,
        x: 50, // center of screen
        y: 60, // near toilet
        velocityX: (Math.random() - 0.5) * 4,
        velocityY: Math.random() * 2 + 1,
        rotation: Math.random() * 360,
      });
    }

    setParticles((prev) => [...prev, ...newParticles]);

    // Update count
    handleClick();
  };

  return (
    <div
      ref={containerRef}
      className="game-screen min-h-screen w-full flex flex-col items-center justify-start p-4 relative overflow-hidden"
      style={{
        background: 'linear-gradient(to bottom, #4c008d, #000000)',
      }}
    >
      {/* Hero Title */}
      <div className="text-center z-10 mt-8 mb-6">
        <h1
          className="text-5xl font-bold tracking-wide bg-gradient-to-r from-yellow-400 via-yellow-300 to-yellow-500 text-transparent bg-clip-text"
          style={{
            textShadow: '0 2px 4px rgba(0,0,0,0.5)',
          }}
        >
          Attack on Toilet
        </h1>
        <p className="text-white mt-3 text-lg max-w-md mx-auto">
          Collect poop, upgrade your flush, and dominate the bathroom!
        </p>
      </div>

      {/* Click Power and Per Second Counters */}
      <div className="z-10 mb-4 flex gap-6">
        <div className="text-center">
          <div className="text-sm text-gray-300">Click Power</div>
          <div
            className="text-2xl font-bold"
            style={{
              color: '#FBBF24',
              textShadow: '0 0 10px rgba(251, 191, 36, 0.7)',
            }}
          >
            {clickPower}
          </div>
        </div>
        <div className="text-center">
          <div className="text-sm text-gray-300">Per Second</div>
          <div
            className="text-2xl font-bold"
            style={{
              color: '#FBBF24',
              textShadow: '0 0 10px rgba(251, 191, 36, 0.7)',
            }}
          >
            {perSecond}
          </div>
        </div>
      </div>

      {/* Poop Counter */}
      <div className={`z-10 mb-8 ${bounceAnimation ? 'animate-bounce-slight' : ''}`}>
        <div
          className="text-6xl font-bold"
          style={{
            color: '#FBBF24',
            textShadow: '0 0 10px rgba(251, 191, 36, 0.7)',
          }}
        >
          {poopCount} Poop Collected
        </div>
      </div>

      {/* Toilet Button */}
      <div className="relative z-10 mb-8 touch-target">
        <button
          onClick={handleToiletClick}
          className="toilet-button w-[150px] h-[150px] rounded-lg shadow-lg transition-transform active:scale-110 flex items-center justify-center"
          style={{
            background: 'linear-gradient(135deg, #ffffff 0%, #f0f0f0 100%)',
            boxShadow: '0 10px 25px rgba(0,0,0,0.5), inset 0 -5px 10px rgba(0,0,0,0.1)',
          }}
        >
          <svg
            width="120"
            height="90"
            viewBox="0 0 120 90"
            className="toilet-svg"
          >
            {/* Toilet base */}
            <rect x="10" y="60" width="100" height="30" rx="5" fill="#f0f0f0" stroke="#ccc" strokeWidth="2" />
            {/* Toilet tank */}
            <rect x="40" y="10" width="40" height="50" rx="5" fill="#e0e0e0" stroke="#ccc" strokeWidth="2" />
            {/* Toilet seat */}
            <rect x="20" y="50" width="80" height="10" rx="5" fill="#d0d0d0" stroke="#ccc" strokeWidth="2" />
            {/* Toilet bowl */}
            <ellipse cx="60" cy="75" rx="30" ry="15" fill="#ffffff" stroke="#ccc" strokeWidth="2" />
            {/* Water in bowl */}
            <ellipse cx="60" cy="80" rx="25" ry="8" fill="#3b82f6" opacity="0.7" />
          </svg>
        </button>
      </div>

      {/* Animated Poop Particles */}
      {particles.map((particle) => (
        <div
          key={particle.id}
          className="poop-particle absolute z-0 text-2xl"
          style={{
            left: `${particle.x}%`,
            top: `${particle.y}%`,
            transform: `rotate(${particle.rotation}deg)`,
            transition: 'transform 0.1s linear',
          }}
        >
          💩
        </div>
      ))}

      {/* Star trails for particles */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {particles.map((particle, index) => (
          <div
            key={`star-${index}`}
            className="star-trail absolute w-1 h-1 bg-yellow-300 rounded-full opacity-70"
            style={{
              left: `${particle.x}%`,
              top: `${particle.y}%`,
              transform: 'translate(-50%, -50%)',
              boxShadow: '0 0 8px 2px rgba(255, 255, 0, 0.6)',
            }}
          />
        ))}
      </div>
    </div>
  );
};

export default GameScreen;

