import { createContext, useContext, useState, useEffect, ReactNode } from 'react';

interface Upgrades {
  clickPower: number;
  perSecond: number;
}

interface UpgradeState {
  id: string;
  title: string;
  owned: boolean;
  cost: number;
  benefit: string;
  type: 'clickPower' | 'perSecond';
}

interface GameContextType {
  poopCount: number;
  clickPower: number;
  perSecond: number;
  upgrades: Upgrades;
  upgradeList: UpgradeState[];
  handleClick: () => void;
  addUpgrade: (type: 'clickPower' | 'perSecond') => void;
  purchaseUpgrade: (upgradeId: string) => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Storage key for localStorage
const STORAGE_KEY = 'toilet-clicker-save';

const GameProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [poopCount, setPoopCount] = useState(326);
  const [clickPower, setClickPower] = useState(1);
  const [perSecond, setPerSecond] = useState(0);
  const [upgrades, setUpgrades] = useState<Upgrades>({
    clickPower: 0,
    perSecond: 0,
  });

  const [upgradeList, setUpgradeList] = useState<UpgradeState[]>([
    {
      id: 'click-1',
      title: 'Enhanced Flush',
      owned: false,
      cost: 50,
      benefit: '+2 Click',
      type: 'clickPower',
    },
    {
      id: 'auto-1',
      title: 'Slow Leak',
      owned: true,
      cost: 0,
      benefit: '+1/sec',
      type: 'perSecond',
    },
    {
      id: 'click-2',
      title: 'Pressure Booster',
      owned: false,
      cost: 150,
      benefit: '+5 Click',
      type: 'clickPower',
    },
    {
      id: 'auto-2',
      title: 'Drip System',
      owned: false,
      cost: 200,
      benefit: '+3/sec',
      type: 'perSecond',
    },
  ]);

  // Load saved game state on mount
  useEffect(() => {
    const loadGame = () => {
      try {
        const savedData = localStorage.getItem(STORAGE_KEY);
        if (savedData) {
          const parsedData = JSON.parse(savedData);

          if (typeof parsedData.poopCount === 'number') setPoopCount(parsedData.poopCount);
          if (typeof parsedData.clickPower === 'number') setClickPower(parsedData.clickPower);
          if (typeof parsedData.perSecond === 'number') setPerSecond(parsedData.perSecond);

          if (Array.isArray(parsedData.upgradeList)) {
            setUpgradeList((prev) => {
              const mergedUpgrades = prev.map((upgrade) => {
                const savedUpgrade = parsedData.upgradeList.find((u: UpgradeState) => u.id === upgrade.id);
                return savedUpgrade ? { ...upgrade, owned: savedUpgrade.owned } : upgrade;
              });
              return mergedUpgrades;
            });
          }
        }
      } catch (error) {
        console.error('Failed to load game:', error);
      }
    };

    loadGame();
  }, []);

  // Save game state whenever key values change
  const saveGame = () => {
    try {
      const saveData = {
        poopCount,
        clickPower,
        perSecond,
        upgradeList: upgradeList.map(({ id, owned }) => ({ id, owned })),
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(saveData));
    } catch (error) {
      console.error('Failed to save game:', error);
    }
  };

  // Save on state changes
  useEffect(() => {
    saveGame();
  }, [poopCount, clickPower, perSecond, upgradeList]);

  const handleClick = () => {
    setPoopCount((prev) => prev + clickPower);
  };

  const addUpgrade = (type: 'clickPower' | 'perSecond') => {
    if (type === 'clickPower') {
      setUpgrades((prev) => ({
        ...prev,
        clickPower: prev.clickPower + 1,
      }));
      setClickPower((prev) => prev + 1);
    } else {
      setUpgrades((prev) => ({
        ...prev,
        perSecond: prev.perSecond + 1,
      }));
      setPerSecond((prev) => prev + 1);
    }
  };

  const purchaseUpgrade = (upgradeId: string) => {
    setUpgradeList((prevUpgrades) => {
      return prevUpgrades.map((upgrade) => {
        if (upgrade.id === upgradeId && !upgrade.owned) {
          if (poopCount >= upgrade.cost) {
            setPoopCount((prev) => prev - upgrade.cost);

            if (upgrade.type === 'clickPower') {
              const powerIncrease = parseInt(upgrade.benefit.replace('+', '').replace(' Click', ''));
              setClickPower((prev) => prev + powerIncrease);
              setUpgrades((prev) => ({
                ...prev,
                clickPower: prev.clickPower + powerIncrease,
              }));
            } else {
              const perSecondIncrease = parseInt(upgrade.benefit.replace('+', '').replace('/sec', ''));
              setPerSecond((prev) => prev + perSecondIncrease);
              setUpgrades((prev) => ({
                ...prev,
                perSecond: prev.perSecond + perSecondIncrease,
              }));
            }

            return { ...upgrade, owned: true };
          }
        }
        return upgrade;
      });
    });
  };

  return (
    <GameContext.Provider value={{ poopCount, clickPower, perSecond, upgrades, upgradeList, handleClick, addUpgrade, purchaseUpgrade }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (context === undefined) {
    throw new Error('useGame must be used within a GameProvider');
  }
  return context;
};

export default GameContext;

export { GameProvider };

import { useEffect, useRef } from 'react';
import { useGame } from '../context/GameContext';
import { useState } from 'react';

interface Particle {
  id: number;
  x: number;
  y: number;
  velocityX: number;
  velocityY: number;
  rotation: number;
}

const useGameLogic = () => {
  const { poopCount, clickPower, perSecond, handleClick, addUpgrade } = useGame();
  const [particles, setParticles] = useState<Particle[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPoopCountRef = useRef(poopCount);

  // Initialize idle particles
  useEffect(() => {
    const newParticles: Particle[] = [];
    const particleCount = 15;

    for (let i = 0; i < particleCount; i++) {
      newParticles.push({
        id: i,
        x: Math.random() * 100,
        y: Math.random() * 100,
        velocityX: (Math.random() - 0.5) * 2,
        velocityY: Math.random() * 2 + 1,
        rotation: Math.random() * 360,
      });
    }

    setParticles(newParticles);
  }, []);

  // Update idle particles animation
  useEffect(() => {
    const interval = setInterval(() => {
      setParticles((prevParticles) =>
        prevParticles.map((particle) => {
          let newX = particle.x + particle.velocityX * 0.2;
          let newY = particle.y + particle.velocityY * 0.2;
          let newRotation = particle.rotation + 2;

          if (newY > 110) {
            newX = Math.random() * 100;
            newY = -10;
            newRotation = Math.random() * 360;
          }

          return {
            ...particle,
            x: newX,
            y: newY,
            rotation: newRotation,
          };
        })
      );
    }, 50);

    return () => clearInterval(interval);
  }, []);

  // Auto-collection effect
  useEffect(() => {
    const interval = setInterval(() => {
      if (perSecond > 0) {
        handleClick();
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [perSecond]);

  // Particle burst on click
  const handleToiletClick = () => {
    handleClick();

    const newParticles: Particle[] = [];
    for (let i = 0; i < 5; i++) {
      newParticles.push({
        id: Date.now() + i,
        x: 50,
        y: 60,
        velocityX: (Math.random() - 0.5) * 4,
        velocityY: Math.random() * 2 + 1,
        rotation: Math.random() * 360,
      });
    }

    setParticles((prev) => [...prev, ...newParticles]);
  };

  // Animate poop count on change
  useEffect(() => {
    if (poopCount !== lastPoopCountRef.current) {
      const animation = setTimeout(() => {
        lastPoopCountRef.current = poopCount;
      }, 300);

      return () => clearTimeout(animation);
    }
  }, [poopCount]);

  return {
    poopCount,
    clickPower,
    perSecond,
    particles,
    containerRef,
    handleToiletClick,
    addUpgrade,
  };
};

export default useGameLogic;

import React, { useState, useEffect } from 'react';
import ReactDOM from 'react-dom/client';
import { GameProvider } from './context/GameContext';
import GameScreen from './components/GameScreen';
import './styles/animations.css';

const LoadingScreen: React.FC<{ isLoading: boolean }> = ({ isLoading }) => {
  return (
    <div
      className={`
        fixed inset-0 z-50 flex items-center justify-center bg-gradient-to-b from-purple-900 to-black
        transition-opacity duration-500 ease-in-out
        ${isLoading ? 'opacity-100' : 'opacity-0 pointer-events-none'}
